function postCrowdSale() public onlyOwner{
        require(presaleEnded, "presale not ended!");
        require(!postsalesEnded, "postsalesEnded");
       // make the pair to get the address
        uniswapPair = uniswapFactory.createPair(
            address(uniswapRouter.WETH()),
            tokenAdd
        );

        uint256 totalETHContributed = address(this).balance;
        uint256 amtDesiredToken = totalETHContributed.mul(2);
        require(amtDesiredToken <= amtToken(), "Unexpected token balance");

        IERC20(tokenAdd).approve(address(uniswapRouter), 0xffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffff);

        // add liquidity
        (,, uint amtLP) = uniswapRouter.addLiquidityETH{value: totalETHContributed}(tokenAdd, amtDesiredToken, 0, 0, address(this), block.timestamp);

        uint amtLPheld = IUniswapV2Pair(uniswapPair).balanceOf(address(this));
        require(amtLPheld == amtLP , "amt LP is different!");

        amtLPlocked = amtLPheld;

        IUniswapV2Pair(uniswapPair).approve(address(pol),amtLPheld);
        // lock liquidity
        if (address(pol)!=address(0)){
            pol.depositToken(uniswapPair, amtLPheld, block.timestamp.add(twoYearSeconds));
            emit Locked(uniswapPair, amtLPheld, block.timestamp.add(twoYearSeconds));
        }

        // remaining tokens sent to treasury
        uint256 totalPresaleAmt = 180 ether;
        uint256 totalTokensForUni = 120 ether;
        uint256 unsoldTokens = totalPresaleAmt.sub(totalETHContributed.mul(3));
        uint256 leftOverNotMatchedWithETH = totalTokensForUni.sub(amtDesiredToken);

        batches.push(Batch(treasury, unsoldTokens.add(leftOverNotMatchedWithETH), block.timestamp + oneWeekSeconds, false));
        emit BatchLocked(treasury, unsoldTokens.add(leftOverNotMatchedWithETH), block.timestamp + oneWeekSeconds);
        postsalesEnded = true;
    }

function stakeLP(uint _amount) public {
        require(emergencyWithdraw == false, "emergency withdraw is on, cannot stake");
        require(_amount > 0, "Can not stake 0 LP tokens");
        require(LPToken.balanceOf(_msgSender()) >= _amount, "Do not have enough LP tokens to stake");

        updatePool();

        if(StakingNFT.nftTokenId(_msgSender()) == 0){
             addStakeholder(_msgSender());
        }

        NFT storage nft = NFTDetails[StakingNFT.nftTokenId(_msgSender())];

        if(nft._LPDeposited > 0) {
            uint _pendingRewards = nft._LPDeposited.mul(accNfyPerShare).div(1e18).sub(nft._rewardDebt);

            if(_pendingRewards > 0) {
                NFYToken.transfer(_msgSender(), _pendingRewards);
                emit RewardsClaimed(_msgSender(), _pendingRewards, StakingNFT.nftTokenId(_msgSender()), now);
            }
        }

        LPToken.transferFrom(_msgSender(), address(this), _amount);
        nft._LPDeposited = nft._LPDeposited.add(_amount);
        totalStaked = totalStaked.add(_amount);

        nft._rewardDebt = nft._LPDeposited.mul(accNfyPerShare).div(1e18);

        emit StakeCompleted(_msgSender(), _amount, StakingNFT.nftTokenId(_msgSender()), nft._LPDeposited, now);
    }

function sponsorProposal(uint256 proposalId) external nonReentrant onlyDelegate {
        // collect proposal deposit from sponsor & store it in MYSTIC until the proposal is processed
        IERC20(depositToken).safeTransferFrom(msg.sender, address(this), proposalDeposit);
        unsafeAddToBalance(ESCROW, depositToken, proposalDeposit);
        Proposal storage proposal = proposals[proposalId];
        require(proposal.proposer != address(0), "!proposed");
        require(proposal.flags[0] == 0, "sponsored");
        require(proposal.flags[3] == 0, "cancelled");
        require(members[proposal.applicant].jailed == 0, "applicant jailed");

        if (proposal.tributeOffered > 0 && userTokenBalances[GUILD][proposal.tributeToken] == 0) {
            require(totalGuildBankTokens < MAX_TOKEN_GUILDBANK_COUNT, "guildbank maxed");
        }

        // whitelist proposal
        if (proposal.flags[4] == 1) {
            require(!tokenWhitelist[address(proposal.tributeToken)], "whitelisted");
            require(!proposedToWhitelist[address(proposal.tributeToken)], "whitelist proposed");
            require(approvedTokens.length < MAX_TOKEN_WHITELIST_COUNT, "whitelist maxed");
            proposedToWhitelist[address(proposal.tributeToken)] = true;

        // guild kick proposal
        } else if (proposal.flags[5] == 1) {
            require(!proposedToKick[proposal.applicant], "kick proposed");
            proposedToKick[proposal.applicant] = true;
        }

        // compute startingPeriod for proposal
        uint256 startingPeriod = max(
            getCurrentPeriod(),
            proposalQueue.length == 0 ? 0 : proposals[proposalQueue[proposalQueue.length - 1]].startingPeriod
        ) + 1;

        proposal.startingPeriod = startingPeriod;
        proposal.sponsor = memberAddressByDelegateKey[msg.sender];
        proposal.flags[0] = 1; // sponsored
        // append proposal to the queue
        proposalQueue.push(proposalId);
        
        emit SponsorProposal(msg.sender, proposal.sponsor, proposalId, proposalQueue.length - 1, startingPeriod);
    }

