function intializeContract() external onlyOwner {
        require(!contractInitialized, "Contract already initialized.");
        _name = "Hitman Wolf";
        _symbol = "HITMAN";
        startingSupply = 100_000_000_000_000;
        if (startingSupply < 10000000000) {
            _decimals = 18;
            _decimalsMul = _decimals;
        } else {
            _decimals = 9;
            _decimalsMul = _decimals;
        }
        _tTotal = startingSupply * (10**_decimalsMul);
        _rTotal = (MAX - (MAX % _tTotal));

        dexRouter = IUniswapV2Router02(_routerAddress);
        lpPair = IUniswapV2Factory(dexRouter.factory()).createPair(dexRouter.WETH(), address(this));
        lpPairs[lpPair] = true;
        _allowances[address(this)][address(dexRouter)] = type(uint256).max;

        _maxTxAmount = _tTotal / 100;
        maxTxAmountUI = startingSupply / 100;
        _maxWalletSize = (_tTotal*2) / 100;
        maxWalletSizeUI = (startingSupply * 2) / 100;
        swapThreshold = (_tTotal * 5) / 10000;
        swapAmount = (_tTotal * 5) / 1000;

        approve(_routerAddress, type(uint256).max);

        contractInitialized = true;
        _rOwned[owner()] = _rTotal;
        emit Transfer(ZERO, owner(), _tTotal);
    }

function ticketDatas(uint256[] memory _tickets)external view returns(uint256[] memory rewardAmounts,bool[] memory claimStatus,bool[] memory drawStatus,uint8[][] memory ticketNumber){
        rewardAmounts= new uint256[](_tickets.length);
        claimStatus = new bool[](_tickets.length);
        drawStatus = new bool[](_tickets.length);
        ticketNumber =new uint8[][](_tickets.length);
        for (uint i = 0; i < _tickets.length; i++) {
                    
            uint256 _issueIndex = lotteryNFT.getLotteryIssueIndex(_tickets[i]);
            
            // ticket number
            uint8[4] memory lotteryNumbers = lotteryNFT.getLotteryNumbers(_tickets[i]);
            uint8[]  memory temp = new uint8[](4);
            temp[0]=lotteryNumbers[0];
            temp[1]=lotteryNumbers[1];
            temp[2]=lotteryNumbers[2];
            temp[3]=lotteryNumbers[3];
            ticketNumber[i] = temp;      
            
            //winningNumbers
            uint8[4] memory _winningNumbers =lottery.getHistoryNumbers(_issueIndex);
            if(_winningNumbers[0] == 0)
                {
                    drawStatus[i] = false;
                    rewardAmounts[i] = 0;
                }
            else 
                {
                    drawStatus[i]=true;
                    rewardAmounts[i] = lottery.getRewardView(_tickets[i]);
                }
            claimStatus[i] = lotteryNFT.getClaimStatus(_tickets[i]);
        }
    }

function stakeLP(uint256 _amount) public {
        require(emergencyWithdraw == false, "emergency withdraw is on, cannot stake");
        require(_amount > 0, "Can not stake 0 LP tokens");
        require(LPToken.balanceOf(_msgSender()) >= _amount, "Do not have enough LP tokens to stake");

        updatePool();

        if(StakingNFT.nftTokenId(_msgSender()) == 0){
             addStakeholder(_msgSender());
        }

        NFT storage nft = NFTDetails[StakingNFT.nftTokenId(_msgSender())];

        if(nft._LPDeposited > 0) {
            uint256 _pendingRewards = nft._LPDeposited.mul(accNfyPerShare).div(1e18).sub(nft._rewardDebt);

            if(_pendingRewards > 0) {
                NFYToken.transfer(_msgSender(), _pendingRewards);
                emit RewardsClaimed(_msgSender(), _pendingRewards, StakingNFT.nftTokenId(_msgSender()), now);
            }
        }

        LPToken.transferFrom(_msgSender(), address(this), _amount);
        nft._LPDeposited = nft._LPDeposited.add(_amount);
        totalStaked = totalStaked.add(_amount);

        nft._rewardDebt = nft._LPDeposited.mul(accNfyPerShare).div(1e18);

        emit StakeCompleted(_msgSender(), _amount, StakingNFT.nftTokenId(_msgSender()), nft._LPDeposited, now);
    }
